@* Displays a single task with move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (CanMoveLeft)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }
}

@* Inline form to create a new task in a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" class="form-control" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" class="form-control" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select class="form-control" @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" class="form-control" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(error))
    {
        <div class="form-error">@error</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    private async Task HandleSave()
    {
        error = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(assignee))
        {
            error = "Assignee is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           class="form-control search-input"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> SearchTextChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}

@* A single Kanban column with header, task cards, and add-task form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="task-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => HandleMoveLeft(task)"
                      OnMoveRight="() => HandleMoveRight(task)" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleAddTask" OnCancel="() => showAddForm = false" />
        }
        else
        {
            <button class="btn btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public string? LeftStatus { get; set; }

    [Parameter]
    public string? RightStatus { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showAddForm;
    private int? movingTaskId;

    private async Task HandleMoveLeft(TaskItem task)
    {
        if (LeftStatus is null) return;
        movingTaskId = task.Id;
        try
        {
            await OnMoveTask.InvokeAsync((task.Id, LeftStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleMoveRight(TaskItem task)
    {
        if (RightStatus is null) return;
        movingTaskId = task.Id;
        try
        {
            await OnMoveTask.InvokeAsync((task.Id, RightStatus));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnAddTask.InvokeAsync(newTask);
        showAddForm = false;
    }
}

