@* Displays a single task with move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (CanMoveLeft)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    [Parameter]
    public bool IsMoving { get; set; }
}

@* Inline form to create a new task in a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" class="form-control" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" class="form-control" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select class="form-control" @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" class="form-control" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn btn-save" @onclick="HandleSave" disabled="@isSaving">
            @(isSaving ? "Saving..." : "Save")
        </button>
        <button class="btn btn-cancel" @onclick="HandleCancel" disabled="@isSaving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(error))
    {
        <div class="form-error">@error</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    private async Task HandleSave()
    {
        error = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(assignee))
        {
            error = "Assignee is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

