                          CanMoveLeft="idx > 0"
                          CanMoveRight="idx < columns.Length - 1"
                          LeftStatus="@(idx > 0 ? columns[idx - 1].Status : null)"
                          RightStatus="@(idx < columns.Length - 1 ? columns[idx + 1].Status : null)"
                          OnMoveTask="HandleMoveTask"
                          OnAddTask="args => HandleAddTask(col.Status, args)" />
        }
    </div>
}

@code {
    private record ColumnDef(string Name, string Status);

    private readonly ColumnDef[] columns =
    [
        new("To Do", "To Do"),
        new("In Progress", "In Progress"),
        new("Done", "Done")
    ];

    private List<TaskItem> tasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredTasksForStatus(string status)
    {
        var query = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var idx = tasks.FindIndex(t => t.Id == args.TaskId);
            if (idx >= 0)
            {
                var old = tasks[idx];
                tasks[idx] = old with { Status = args.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            tasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

