+.board-error {
+    text-align: center;
+    padding: 2rem;
+    font-size: 1.1rem;
+}
+
+.board-error {
+    color: #dc3545;
+}
+
+/* ── Stats bar ── */
+.board-stats {
+    display: flex;
+    gap: 1.5rem;
+    padding: 0.75rem 1rem;
+    background: #f8f9fa;
+    border-radius: 8px;
+    margin-bottom: 1rem;
+    flex-wrap: wrap;
+}
+
+.stat-item {
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+    min-width: 70px;
+}
+
+.stat-value {
+    font-size: 1.4rem;
+    font-weight: 700;
+}
+
+.stat-label {
+    font-size: 0.75rem;
+    color: #6c757d;
+    text-transform: uppercase;
+}
+
+.stat-overdue .stat-value {
+    color: #dc3545;
+}
+
+/* ── Search bar ── */
+.search-bar {
+    margin-bottom: 1rem;
+}
+
+.search-input {
+    width: 100%;
+    max-width: 400px;
+    padding: 0.5rem 0.75rem;
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    font-size: 0.95rem;
+}
+
+/* ── Kanban board grid ── */
+.kanban-board {
+    display: flex;
+    gap: 1rem;
+    align-items: flex-start;
+    overflow-x: auto;
+    padding-bottom: 1rem;
+}
+
+/* ── Column ── */
+.kanban-column {
+    flex: 1 1 0;
+    min-width: 260px;
+    background: #f1f3f5;
+    border-radius: 8px;
+    display: flex;
+    flex-direction: column;
+}
+
+.column-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    padding: 0.75rem 1rem;
+    border-bottom: 2px solid #dee2e6;
+}
+
+.column-header h3 {
+    margin: 0;
+    font-size: 1rem;
+    font-weight: 600;
+}
+
+.task-count {
+    background: #dee2e6;
+    border-radius: 12px;
+    padding: 0.1rem 0.55rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+.column-body {
+    padding: 0.5rem;
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+    min-height: 80px;
+}
+
+.column-footer {
+    padding: 0.5rem;
+}
+
+/* ── Task card ── */
+.task-card {
+    background: #fff;
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    padding: 0.75rem;
+    box-shadow: 0 1px 2px rgba(0,0,0,0.06);
+}
+
+.task-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: flex-start;
+    gap: 0.5rem;
+    margin-bottom: 0.4rem;
+}
+
+.task-title {
+    font-weight: 600;
+    font-size: 0.9rem;
+    word-break: break-word;
+}
+
+.priority-badge {
+    font-size: 0.7rem;
+    font-weight: 600;
+    padding: 0.15rem 0.5rem;
+    border-radius: 10px;
+    text-transform: uppercase;
+    white-space: nowrap;
+}
+
+.priority-high {
+    background: #f8d7da;
+    color: #842029;
+}
+
+.priority-medium {
+    background: #fff3cd;
+    color: #664d03;
+}
+
+.priority-low {
+    background: #d1e7dd;
+    color: #0f5132;
+}
+
+.task-meta {
+    display: flex;
+    justify-content: space-between;
+    font-size: 0.8rem;
+    color: #6c757d;
+    margin-bottom: 0.5rem;
+}
+
+.task-actions {
+    display: flex;
+    gap: 0.35rem;
+}
+
+/* ── Buttons ── */
+.btn {
+    cursor: pointer;
+    border: none;
+    border-radius: 4px;
+    padding: 0.35rem 0.65rem;
+    font-size: 0.8rem;
+    background: #e9ecef;
+    color: #212529;
+}
+
+.btn:hover {
+    background: #ced4da;
+}
+
+.btn:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+}
+
+.btn-sm {
+    padding: 0.2rem 0.45rem;
+    font-size: 0.75rem;
+}
+
+.btn-move {
+    background: #e2e6ea;
+}
+
+.btn-add-task {
+    width: 100%;
+    background: #e9ecef;
+    font-weight: 600;
+}
+
+.btn-save {
+    background: #0d6efd;
+    color: #fff;
+}
+
+.btn-save:hover {
+    background: #0b5ed7;
+}
+
+.btn-cancel {
+    background: #e9ecef;
+}
+
+/* ── Add task form ── */
+.add-task-form {
+    background: #fff;
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    padding: 0.75rem;
+}
+
+.add-task-form .form-group {
+    margin-bottom: 0.5rem;
+}
+
+.add-task-form label {
+    display: block;
+    font-size: 0.75rem;
+    font-weight: 600;
+    margin-bottom: 0.15rem;
+    color: #495057;
+}
+
+.add-task-form .form-control {
+    width: 100%;
+    padding: 0.35rem 0.5rem;
+    border: 1px solid #ced4da;
+    border-radius: 4px;
+    font-size: 0.85rem;
+    box-sizing: border-box;
+}
+
+.form-actions {
+    display: flex;
+    gap: 0.35rem;
+    margin-top: 0.5rem;
+}
+
+.form-error {
+    color: #dc3545;
+    font-size: 0.8rem;
+    margin-top: 0.35rem;
+}
+

